// Function to calculate the sum of all even numbers in an array
function sumEvenNumbers(array) {
    // Initialize a variable to store the sum of even numbers
    let sum = 0;

    // Iterate over each number in the array
    for (let i = 0; i < array.length; i++) {
        // Check if the current number is even
        if (array[i] % 2 === 0) {
            // If the number is even, add it to the sum
            sum += array[i];
        }
    }

    // Return the sum of even numbers
    return sum;
}

// Example usage:
let numbers = [1, 2, 3, 4, 5, 6];
console.log(sumEvenNumbers(numbers));  // Output: 12

 Here's a JavaScript function that calculates the sum of all even numbers in an array:

```javascript
function sumEvenNumbers(arr) {
  return arr.reduce((sum, num) => {
    if (num % 2 === 0) {
      sum += num;
    }
    return sum;
  }, 0);
}
```

This function uses the `reduce` method to iterate through the array and accumulate the sum of even numbers. The initial value of the accumulator (`sum`) is set to 0.

You can use this function like this:

```javascript
const numbers = [1, 2, 3, 4, 5, 6];
console.log(sumEvenNumbers(numbers)); // Output: 12
```

This will output `12`, which is the sum of the even numbers in the array (`2`, `4`, and `6`).

